const invoices = $input.first().json;
if (!Array.isArray(invoices) || invoices.length === 0) return [];
// Une seule relance par client (regroupement)
const byClient = {};
for (const i of invoices) {
  const key = i.customer_name || i.id;
  if (!byClient[key]) byClient[key] = [];
  byClient[key].push(i);
}
return Object.entries(byClient).map(([client, invs]) => ({
  json: {
    customer: client,
    invoices: invs,
    total: invs.reduce((s, i) => s + (parseFloat(i.amount_eur) || 0), 0).toFixed(2),
    invoice_list: invs.map(i => `${i.invoice_number} (${i.amount_eur} €, ${i.days_overdue}j de retard)`).join(', '),
  },
}));

